aggregationScript:
// 用户信息聚合脚本
const userData = results.userService || {};
const orderData = results.orderService || {};
const paymentData = results.paymentService || {};

return {
  success: true,
  user: {
    id: userData.id || params.userId,
    name: userData.name || '未知用户',
    email: userData.email,
    phone: userData.phone
  },
  orders: {
    total: orderData.total || 0,
    pending: orderData.pending || 0,
    completed: orderData.completed || 0
  },
  payment: {
    balance: paymentData.balance || 0,
    points: paymentData.points || 0,
    level: paymentData.level || '普通会员'
  },
  aggregatedAt: Date.now()
};

// 订单创建聚合脚本
const createResult = results.createOrder || {};
const inventoryResult = results.updateInventory || {};

if (!createResult.success) {
  throw new Error('订单创建失败: ' + (createResult.error || '未知错误'));
}

return {
  success: true,
  orderId: createResult.orderId,
  orderNo: createResult.orderNo,
  inventoryUpdated: inventoryResult.success || false,
  createdAt: Date.now()
};
